 namespace Pmpr\Common\Foundation\Data; use Pmpr\Common\Foundation\Manipulate\ManipulateServer; class View extends Data { const LIST_VIEW = "\154\151\x73\164\x5f\166\x69\x65\x77"; const GRID_VIEW = "\147\162\x69\x64\x5f\166\151\145\x77"; protected ?string $name = ''; protected ?string $icon = ''; protected ?string $title = ''; protected ?int $priority = 0; protected bool $isDefault = false; public function getName() : ?string { return $this->name; } public function setName(?string $Llson) : self { $this->name = $Llson; return $this; } public function getIcon() : ?string { return $this->icon; } public function setIcon(?string $DMAEw) : self { $this->icon = $DMAEw; return $this; } public function getTitle() : ?string { return $this->title; } public function setTitle(?string $aZcKX) : self { $this->title = $aZcKX; return $this; } public function isEnable() : bool { $iBTb2 = self::getView(); return $iBTb2 && $this->getName() == $iBTb2 || !$iBTb2 && $this->isDefault(); } public function getPriority() : ?int { return $this->priority; } public function setPriority(?int $gcOru) : self { $this->priority = $gcOru; return $this; } public function isDefault() : bool { return $this->isDefault; } public function setIsDefault(bool $kE_Hs) : self { $this->isDefault = $kE_Hs; return $this; } public static function getView() { return ManipulateServer::get(self::LIST_VIEW, false); } public static function isView($iBTb2) { return self::getView() == $iBTb2; } }
